SELECT DISTINCT T1.user_id
FROM access_logs AS T1
WHERE T1.access_type = 'review' AND T1.user_id NOT IN (SELECT author_id FROM change_requests);

SELECT DISTINCT change_number
FROM change_requests
WHERE change_type = 'major revision';

SELECT AVG(number_of_requests) AS average_requests
FROM (
  SELECT author_id, COUNT(*) as number_of_requests
  FROM change_requests
  GROUP BY author_id
) as subquery;

SELECT document_name
FROM documents
WHERE document_name LIKE '%Guidelines%';
